function createCandlestickChart(ctx, data, label = "Stock Price") {
  return new Chart(ctx, {
    type: "candlestick",
    data: { datasets: [{ label, data }] },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: {
          type: "time",
          adapters: { date: { zone: "utc" } },
          ticks: { source: "data", maxRotation: 0, autoSkip: true, autoSkipPadding: 75, sampleSize: 100 },
        },
        y: { beginAtZero: false },
      },
      plugins: {
        legend: { display: true },
        tooltip: { mode: "index", intersect: false },
      },
      interaction: { mode: "nearest", axis: "x", intersect: false },
    },
  });
}